def diagonal_moves(q, queries):
    n = len(queries)
    moves = [0] * n
    for i in range(n):
        moves[i] = queries[i][2]

    max_diagonal_moves = 0
    for i in range(n):
        x, y, k = queries[i]
        dx, dy = x - n + 1, y - n + 1
        if dx == dy:
            max_diagonal_moves = max(max_diagonal_moves, k)
            continue
        if dx > dy:
            dx, dy = dx - k, dy - k
        if dx < 0:
            dx, dy = dx + k, dy + k
        if dy < 0:
            dx, dy = dx + k, dy + k
        if dx == dy:
            max_diagonal_moves = max(max_diagonal_moves, k)
            continue
        if dx > dy:
            dx, dy = dx - k, dy - k
        if dx < 0:
            dx, dy = dx + k, dy + k
        if dy < 0:
            dx, dy = dx + k, dy + k

    return max_diagonal_moves

