from collections import deque

def diagonal_moves(q, queries):
    n = len(queries)
    visited = set()
    max_diagonal_moves = 0

    for i in range(n):
        x, y, k = queries[i]
        if (x, y) not in visited:
            visited.add((x, y))
            queue = deque([(x, y)])
            while queue:
                x, y = queue.popleft()
                if x == n and y == m:
                    return -1
                for dx, dy in [(-1, 0), (1, 0), (0, -1), (0, 1)]:
                    nx, ny = x + dx, y + dy
                    if 0 <= nx < n and 0 <= ny < m and (nx, ny) not in visited:
                        visited.add((nx, ny))
                        queue.append((nx, ny))
                        if k > 0:
                            k -= 1
                        elif k < k_i:
                            k += 1
                        else:
                            max_diagonal_moves = max(max_diagonal_moves, k)

    return max_diagonal_moves

